# create_mock_model.py\n\n"""\nUtility script to generate a simple mock scikit‑learn model for the InsureGuard engine.\nIt trains a LogisticRegression on trivial synthetic data and saves it as `ml_model.joblib`\nin the same directory as this script. Run it once before starting the FastAPI server.\n\n```bash\npython backend/app/modules/create_mock_model.py\n```\n"""\n\nimport os\nimport joblib\nimport numpy as np\nfrom sklearn.linear_model import LogisticRegression\n\n# Synthetic dataset – features: coverage_limit, premium, hashed entity\nX = np.array([\n    [500000, 1500, 123],\n    [1000000, 3000, 456],\n    [200000, 800, 789],\n    [750000, 2500, 321],\n])\n# Binary target – 1 indicates high risk, 0 low risk\ny = np.array([1, 1, 0, 1])\n\nmodel = LogisticRegression()\nmodel.fit(X, y)\n\nmodel_path = os.path.join(os.path.dirname(__file__), "ml_model.joblib")\njoblib.dump(model, model_path)\nprint(f"Mock model saved to {model_path}")\n
